await cms.first({
  type: BlogPostSchema,
  // Filter using search terms
  search: 'querying',
  // Filter by fields
  // This filters the blogposts with author 'alinea'
  filter: {
    author: 'alinea'
  }
})

/*
Filter helpers:
lt  = less than            
lte = less than or equal  

gt = greater than
gte = greater than or equal
*/

const today = new Date().toISOString()

// Getting the posts published in 2023
await cms.find({
  type: BlogPostSchema,

  filter: {
    author: 'alinea',
    publishedDate: {
      lt: '2024-01-01',
      gte: '2023-01-01'
    }
  }
})

// Getting future events
await cms.find({
  type: Event,

  filter: {
    date: {gte: today}
  }
})
